import { createRouter, createWebHistory } from 'vue-router'
import Home from '@/App'
import Configuracion from '@/views/configuracion/Configuracion'
import About from '@/views/About'
import Login from '@/views/login/Login'

import { useAuthStore } from '@/service/auth' // Asegúrate de tener un store de autenticación

const routes = [
  {
    path: '/login',
    name: 'login',
    component: Login
  },
  {
    path: '/',
    name: 'home',
    component: Home
  },
  {
    path: '/configuracion',
    name: 'configuracion',
    component: Configuracion
  },
  {
    path: '/about',
    name: 'about',
    component: About
  },
  {//catch 404
    path: '/:catchAll(.*)',
    name: 'notFound',
    component: About
  }
  //Route Guards
]

const router = createRouter({
  history: createWebHistory(process.env.BASE_URL),
  routes
})

router.beforeEach((to, from, next) => {
  const authStore = useAuthStore();
  // Si el usuario está autenticado y la ruta a la que va es '/login' o '/register',
  // lo redirigimos a la página de inicio ('/')
  console.log(authStore.isLoggedIn);
  if (authStore.isLoggedIn) {
    next({ name: 'home' }); // Redirige al usuario al home
  } else {
    // Si no se cumple la condición, permite el acceso
    next();
  }
});

export default router
